import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('role');
    navigate('/login');
  };

  return (
    <nav className="bg-white shadow">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex">
            <div className="flex-shrink-0 flex items-center">
              <Link to="/" className="text-2xl font-bold text-primary">SmartPoint</Link>
            </div>
            <div className="hidden sm:ml-6 sm:flex sm:space-x-8 items-center">
              <Link to="/" className="text-gray-900 hover:text-primary transition-colors hover-underline">Home</Link>
              {token && <Link to="/dashboard" className="text-gray-900 hover:text-primary transition-colors">Dashboard</Link>}
            </div>
          </div>
          <div className="flex items-center space-x-4">
            {!token ? (
              <>
                <Link to="/login" className="text-gray-900 hover:text-primary">Login</Link>
                <Link to="/register" className="btn-primary">Sign up</Link>
              </>
            ) : (
              <button onClick={handleLogout} className="text-gray-900 hover:text-red-600 transition-colors">
                Logout
              </button>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
